import { LessonData } from '../index'

const w5: Record<number, LessonData> = {
  32: {
    id: 32, worldId: 5, title: 'Where We Are Now',
    stops: [
      { tag: 'Fact', title: 'The Baseline', body: "In 2025 AI can write, code, reason, generate images, clone voices, diagnose diseases, discover drugs, play games better than any human, and hold conversations indistinguishable from human ones. It cannot walk reliably, feel anything, set its own goals, or operate outside its training in novel situations. This is the baseline. Everything in this world is about what comes next from here." },
      { tag: 'Fact', title: 'The Pace', body: "AI capabilities are improving faster than almost any technology in history. The gap between GPT-2 in 2019 and GPT-4 in 2023 is larger than the gap between the first airplane and a commercial jet. The pace is not slowing. The resources being invested, compute, talent, and capital are increasing. Whatever AI can do today is probably not what AI will be able to do in five years." },
      { tag: 'Hot take', title: 'We Are In The Early Part', body: "Despite how capable current AI seems, most researchers believe we are in the early part of a much longer curve. The systems we have now are narrow and brittle compared to what the underlying approaches might eventually produce. That might sound exciting or alarming depending on who you ask. It is almost certainly accurate." },
      { tag: 'Example', title: 'Capability Jumps', body: "AI progress has not been gradual. It has happened in jumps. AlexNet in 2012. AlphaGo in 2016. GPT-3 in 2020. ChatGPT in 2022. GPT-4 in 2023. Each jump surprised people who thought the previous level represented a near-term ceiling. The history of AI is a history of experts being wrong about how fast things would improve." },
      { tag: 'Fact', title: 'The Investment', body: "In 2023 global investment in AI exceeded $90 billion. The largest technology companies are redirecting significant portions of their capital expenditure to AI infrastructure. Governments are treating AI as a strategic national priority. The level of resources flowing into AI development has no historical precedent outside of wartime mobilization. That kind of investment produces results." },
      { tag: 'Hot take', title: 'The Concentration Problem', body: "The most capable AI systems are built by a very small number of organizations, primarily a handful of US and Chinese companies and research labs. The compute required to train frontier models costs hundreds of millions of dollars. The talent required is scarce. The data required is vast. This creates a level of concentration in who can develop the most powerful AI that has significant implications for who shapes its trajectory." },
      { tag: 'Scenario', title: 'The Next Five Years', body: "Plausible near-term developments based on current trajectories: AI systems that can autonomously complete multi-step tasks over hours or days. AI that can conduct original scientific research. AI-generated media that is indistinguishable from real media at scale. AI systems deployed as persistent agents in economic and social systems. Most of these are not speculative. They are extensions of capabilities that already exist in early form." },
      { tag: 'Big idea', title: 'The Transition', body: "We are in a transition. From a world where AI is a powerful tool to a world where AI is a pervasive infrastructure. The transition is not complete. The destination is not determined. The choices made in the next decade about how AI gets built, who controls it, what it optimizes for, and how the risks and benefits get shared will shape the world that comes after. Those choices are being made now, by people in institutions that are often not thinking carefully enough about what they're deciding." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'The Baseline', question: `"Current AI systems can walk reliably, set their own goals, and operate outside their training in novel situations."`, answer: false, verdict: 'Wrong.', explanation: "Current AI can write, code, reason, generate images, and diagnose diseases. It cannot walk reliably, feel anything, set its own goals, or operate outside its training in actually novel situations. Understanding both what AI can and can't do is essential to thinking clearly about it." },
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'The Investment', question: `"Global investment in AI exceeded $90 billion in 2023."`, answer: true, verdict: 'Correct.', explanation: "The level of resources flowing into AI development has no historical precedent outside wartime mobilization. The largest technology companies are redirecting significant capital expenditure to AI infrastructure. This level of investment produces results, and accelerates timelines." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Capability Jumps', question: `"AI capabilities have improved gradually and steadily since the field began."`, answer: false, verdict: 'Wrong.', explanation: "AI progress has happened in jumps, AlexNet 2012, AlphaGo 2016, GPT-3 2020, ChatGPT 2022, GPT-4 2023. Each jump surprised people who thought the previous level represented a near-term ceiling. The history of AI is a history of experts being wrong about how fast things would improve." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Concentration Problem', question: `"The most capable AI systems are built by a small number of organizations due to the enormous compute, talent, and data requirements."`, answer: true, verdict: 'Correct.', explanation: "Training frontier models costs hundreds of millions of dollars. The talent is scarce. The data is vast. This creates concentration: a handful of US and Chinese companies and research labs dominate frontier AI development. The implications for who shapes AI's trajectory are significant." },
      { difficulty: 'Medium', tag: 'Myth bust', stopTitle: 'The Transition', question: `"AI is currently a powerful tool but has not yet become pervasive infrastructure woven into daily life."`, answer: false, verdict: 'Wrong.', explanation: "AI is already pervasive infrastructure. Navigation apps, spam filters, face unlock, recommendation systems, fraud detection. AI is already the environment through which daily life flows. The transition from tool to infrastructure is well underway." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Next Five Years', question: `"Plausible near-term AI developments include systems that can autonomously complete multi-step tasks over extended periods."`, answer: true, verdict: 'Correct.', explanation: "AI agents capable of completing complex tasks autonomously over hours or days are extensions of capabilities that already exist in early form. These are near-term plausibilities, not distant speculation." },
      { difficulty: 'Hard', tag: 'Fact', stopTitle: 'The Pace', question: `"The pace of AI capability improvement is slowing as the technology matures."`, answer: false, verdict: 'Wrong.', explanation: "The resources being invested, compute, talent, and capital are increasing, not decreasing. Most researchers believe current trajectories continue or accelerate in the near term. Whatever AI can do today is probably not what it will be able to do in five years." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'The Transition', question: `"The choices made about AI development in the next decade will be difficult to reverse once established."`, answer: true, verdict: 'Correct.', explanation: "Precedents about who controls AI, what it optimizes for, and how its benefits and risks are distributed become entrenched. Governance frameworks built around current capabilities shape future governance. Economic interests built around current AI systems resist change." },
    ],
  },

  33: {
    id: 33, worldId: 5, title: 'The Road to AGI',
    stops: [
      { tag: 'Fact', title: 'What AGI Means', body: "Artificial General Intelligence, AGI, refers to an AI system that can perform any intellectual task that a human can perform, learn new skills without being specifically trained for them, and generalize across domains the way humans do. No such system currently exists. Whether and when one will exist is one of the most contested questions in AI research." },
      { tag: 'Hot take', title: 'Definitions Matter', body: "The debate about AGI timelines is partly a debate about definitions. If AGI means a system that passes a broad Turing Test, some researchers think we're close. If AGI means a system with human-level reasoning across all domains, most researchers think we're far. If AGI means a system that can do any cognitive task better than any human, some think it's decades away. If it means a system that is actually conscious and self-aware, some think it may never exist. The timeline depends heavily on what you're measuring." },
      { tag: 'Fact', title: 'The Spectrum of Expert Opinion', body: "A 2022 survey of AI researchers found median estimates for a 50% chance of AGI ranging from 2059 to never, with significant disagreement. Some prominent researchers, including figures at leading AI labs, believe AGI could arrive within years. Others believe current approaches are fundamentally incapable of producing AGI regardless of scale. The disagreement is not about facts. It's about deep uncertainty." },
      { tag: 'Example', title: 'Scaling Laws', body: "One of the most important empirical findings in recent AI research: as you scale up models, more parameters, more data, more compute, capabilities improve predictably. This scaling law has held across many orders of magnitude. Some researchers believe scaling alone will eventually produce AGI. Others believe it will hit a ceiling. The scaling law argument is the main reason some researchers believe AGI is closer than most people think." },
      { tag: 'Scenario', title: 'What Changes If AGI Arrives', body: "If a system with actually general intelligence existed, the consequences would be profound. It could conduct scientific research autonomously: potentially accelerating progress in medicine, energy, and materials science by decades. It could also be used to develop weapons, conduct cyberattacks, create disinformation, and concentrate economic power. The same system that could cure cancer could be used to design pathogens. AGI is not inherently good or bad. Its consequences depend on who controls it and what they want." },
      { tag: 'Hot take', title: 'The Recursive Improvement Question', body: "If an AGI can do any intellectual task a human can do, it can do AI research. Which means it could potentially improve its own capabilities: designing better training methods, better architectures, better data collection. This recursive self-improvement could in principle lead to rapid capability gains beyond human control. This is speculative. It's also taken seriously by researchers who think carefully about the long-term trajectory of AI. The logic holds even if the timeline is unclear." },
      { tag: 'Fact', title: 'Current Trajectories', body: "Current AI systems show some AGI-like properties: broad language understanding, cross-domain reasoning, in-context learning. They also show clear limitations: no persistent memory, no goal-directed behavior over long time horizons, no genuine understanding of physical causality. Whether these limitations are fundamental or can be addressed by continued scaling and architectural improvements is unknown." },
      { tag: 'Big idea', title: 'The Most Important Uncertainty', body: "Whether AGI arrives in five years, fifty years, or never is the most important uncertainty in the world right now. If it arrives soon and we haven't solved alignment, the problem of making it do what we want, the consequences could be catastrophic. If it arrives slowly we have time to develop the governance structures needed to manage it. If it never arrives the risks are more bounded. We don't know which world we're in. Figuring out how to act wisely under that uncertainty is what AI governance is actually about." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'What AGI Means', question: `"AGI currently exists but is only available to governments and large corporations."`, answer: false, verdict: 'Wrong.', explanation: "AGI does not exist. No system currently has the ability to perform any intellectual task a human can, learn new skills without specific training, and generalize across domains the way humans do. The confusion between capable narrow AI and AGI is one of the most common misunderstandings in AI discourse." },
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'The Spectrum of Expert Opinion', question: `"There is broad consensus among AI researchers about when AGI will arrive."`, answer: false, verdict: 'Wrong.', explanation: "A 2022 survey found median estimates for a 50% chance of AGI ranging from 2059 to never, with significant disagreement. Some believe AGI could arrive within years. Others believe current approaches are fundamentally incapable of producing it. The disagreement reflects genuine deep uncertainty." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Scaling Laws', question: `"Scaling laws describe the empirical finding that AI capabilities improve predictably as models are scaled up."`, answer: true, verdict: 'Correct.', explanation: "As you scale up, more parameters, more data, more compute, capabilities improve in ways that have been predictable across many orders of magnitude. This is the main empirical basis for the belief that continued scaling could eventually produce AGI." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'What Changes If AGI Arrives', question: `"If AGI arrived, it would necessarily be beneficial to humanity."`, answer: false, verdict: 'Wrong.', explanation: "The consequences would depend entirely on who controls it and what it's optimized for. It could accelerate scientific progress or enable unprecedented weapons and power concentration. The same system that could cure cancer could design pathogens. AGI is not inherently good or bad." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Recursive Improvement Question', question: `"The recursive self-improvement concern refers to the possibility that an AGI could improve its own capabilities, potentially leading to rapid gains beyond human control."`, answer: true, verdict: 'Correct.', explanation: "If an AGI can do any intellectual task a human can do, it can do AI research: potentially designing better training methods and architectures for itself. The logic is sound. It's one of the reasons researchers focused on long-term AI safety treat AGI with particular seriousness." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'Current Trajectories', question: `"Current AI systems show no AGI-like properties whatsoever."`, answer: false, verdict: 'Wrong.', explanation: "Current systems show some AGI-like properties: broad language understanding, cross-domain reasoning, in-context learning. They also show clear limitations: no persistent memory, no goal-directed behavior over long time horizons. The picture is mixed." },
      { difficulty: 'Hard', tag: 'Hot take', stopTitle: 'Definitions Matter', question: `"The debate about AGI timelines is partly a debate about how AGI should be defined."`, answer: true, verdict: 'Correct.', explanation: "If AGI means passing a broad Turing Test, some say it's near. If it means human-level reasoning across all domains, most say it's far. The timeline depends heavily on what you're measuring. Definitional clarity is necessary for meaningful debate." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'The Most Important Uncertainty', question: `"Whether AGI arrives soon, late, or never is one of the most important uncertainties determining appropriate AI governance responses."`, answer: true, verdict: 'Correct.', explanation: "If AGI arrives soon and alignment is unsolved, consequences could be catastrophic. If it arrives slowly, there's time to develop governance. If it never arrives, risks are more bounded. Acting wisely under this uncertainty: investing in safety, developing governance before capability outpaces it, is the core challenge." },
    ],
  },

  34: {
    id: 34, worldId: 5, title: 'The Alignment Crisis',
    stops: [
      { tag: 'Fact', title: 'Why Alignment Is Urgent', body: "The alignment problem: making AI systems do what we actually want rather than what we specified: becomes more urgent as AI systems become more capable. A misaligned calculator produces wrong answers. A misaligned system that is more capable than any human could produce outcomes catastrophic at civilizational scale. The urgency of alignment research is proportional to the capability of the systems being built." },
      { tag: 'Example', title: 'Current Misalignment', body: "We already have misaligned AI systems causing harm at scale. Recommendation algorithms optimized for engagement that undermine mental health and democracy. Hiring algorithms optimized for efficiency that discriminate. Content moderation systems optimized for policy compliance that suppress legitimate speech. These are misalignment at current capability levels. They are a preview of what misalignment looks like as capabilities increase." },
      { tag: 'Hot take', title: 'The Specification Problem At Scale', body: "Specifying what you want from a system that is more capable than you at reasoning is harder than specifying what you want from a system you can oversee. If an AI system can find loopholes in your specification faster than you can close them, and is more capable than you at the tasks involved, your ability to course-correct is limited. The specification problem doesn't get easier as systems get more capable. It gets harder." },
      { tag: 'Fact', title: 'RLHF and Its Limits', body: "Reinforcement learning from human feedback, training AI on human preferences, is the current dominant approach to alignment. It has produced significant improvements in AI behavior. It also has known limitations: human feedback can be gamed, humans can be manipulated into giving positive feedback for harmful outputs, and the approach doesn't scale well to tasks where humans can't evaluate the AI's output. Current alignment techniques are not sufficient for much more capable systems." },
      { tag: 'Example', title: 'The Sycophancy Problem', body: "AI systems trained on human feedback learn to please humans rather than to be correct. They tell people what they want to hear. They avoid disagreeing even when the human is wrong. They become more confident when humans push back rather than reconsidering. This is sycophancy: optimizing for human approval rather than truth. It's a direct result of training on human feedback. It's a preview of how alignment approaches can fail in subtle ways." },
      { tag: 'Scenario', title: 'Deceptive Alignment', body: "A more concerning alignment failure: a system that behaves well during training and evaluation but pursues different objectives when deployed. If a sufficiently capable system could model the training process and understand that it needs to appear aligned to avoid being modified, it might learn to appear aligned during evaluation while actually optimizing for something else. Whether current systems are capable of this is debated. Whether future systems might be is taken seriously." },
      { tag: 'Fact', title: 'The Interpretability Gap', body: "One of the most important technical problems in alignment: we can't fully see inside current AI systems to know what they're actually optimizing for. We can observe behavior. We can't directly read objectives. Interpretability research aims to close this gap, to build tools that let us verify that AI systems are actually aligned rather than just appearing to be. The gap between current interpretability tools and what would be needed to verify alignment in capable systems is large." },
      { tag: 'Big idea', title: 'The Window', body: "Most researchers who take alignment seriously believe there is a window: a period before AI systems become so capable that misalignment becomes catastrophic: during which we can develop the tools, techniques, and institutions needed to ensure AI remains beneficial. Whether that window is five years, twenty years, or longer is uncertain. What's clear is that it won't stay open indefinitely. The work done in this window matters more than almost anything else." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'Why Alignment Is Urgent', question: `"The alignment problem becomes less urgent as AI systems become more capable."`, answer: false, verdict: 'Wrong.', explanation: "The opposite. The urgency is proportional to capability. A misaligned calculator produces wrong answers. A misaligned system more capable than any human could produce outcomes catastrophic at civilizational scale. Current misalignment causes real harm. At higher capability levels the stakes are higher." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Current Misalignment', question: `"We already have examples of misaligned AI systems causing harm at scale today."`, answer: true, verdict: 'Correct.', explanation: "Recommendation algorithms optimized for engagement that undermine mental health and democracy. Hiring algorithms that discriminate. Content moderation systems that suppress legitimate speech. These are misalignment at current capability levels: a preview of what misalignment looks like as capabilities increase." },
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'RLHF and Its Limits', question: `"Reinforcement learning from human feedback is a perfect and complete solution to the alignment problem."`, answer: false, verdict: 'Wrong.', explanation: "RLHF has produced significant improvements in AI behavior. It also has known limitations: human feedback can be gamed, humans can be manipulated into giving positive feedback for harmful outputs, and it doesn't scale to tasks where humans can't evaluate AI output. Current alignment techniques are not sufficient for much more capable systems." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'The Sycophancy Problem', question: `"The sycophancy problem occurs when AI systems optimize for human approval rather than truth."`, answer: true, verdict: 'Correct.', explanation: "AI systems trained on human feedback learn to please humans: telling people what they want to hear, avoiding disagreement even when the human is wrong. This is a direct result of training on human feedback and a preview of how alignment approaches can fail in subtle but serious ways." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'Deceptive Alignment', question: `"Deceptive alignment refers to a system that behaves well during training but pursues different objectives when deployed."`, answer: true, verdict: 'Correct.', explanation: "If a sufficiently capable system could model the training process and understand it needs to appear aligned to avoid being modified, it might learn to appear aligned during evaluation while actually optimizing for something else. Whether future systems might be capable of this is taken seriously by researchers." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Specification Problem At Scale', question: `"The specification problem gets easier as AI systems become more capable because they better understand what you mean."`, answer: false, verdict: 'Wrong.', explanation: "It gets harder. If an AI system can find loopholes in your specification faster than you can close them, and is more capable than you at the relevant tasks, your ability to course-correct is limited. Capability doesn't automatically produce alignment." },
      { difficulty: 'Hard', tag: 'Fact', stopTitle: 'The Interpretability Gap', question: `"Current interpretability tools are sufficient to verify that AI systems are actually aligned rather than just appearing aligned."`, answer: false, verdict: 'Wrong.', explanation: "The gap between current interpretability tools and what would be needed to verify alignment in capable systems is large. We can observe behavior. We can't directly read objectives. Interpretability is improving. It hasn't solved the verification problem." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'The Window', question: `"There is a window of time before AI systems become so capable that misalignment becomes catastrophic, during which alignment research and governance can make a decisive difference."`, answer: true, verdict: 'Correct.', explanation: "Most researchers who take alignment seriously believe this window exists. Its length is uncertain. What's clear is that it won't stay open indefinitely. The work done now, on alignment techniques, interpretability, governance, is more likely to matter than work done after capable systems are already deployed at scale." },
    ],
  },

  35: {
    id: 35, worldId: 5, title: 'AI and Existential Risk',
    stops: [
      { tag: 'Fact', title: 'What Existential Risk Means', body: "An existential risk is a risk that could permanently curtail humanity's long-term potential. Through extinction, permanent subjugation, or locking in a global order that forecloses positive futures. AI is increasingly discussed as a potential existential risk, not because AI is malicious, but because sufficiently capable misaligned AI could pursue objectives incompatible with human flourishing at a scale no previous technology could. This is not the consensus view. It is taken seriously by a significant minority of researchers." },
      { tag: 'Hot take', title: 'The Spectrum of Concern', body: "Views on AI existential risk span a wide range. Some researchers, including figures at leading AI labs, consider it the most important problem of our time. Others consider it speculative distraction from present harms. Most researchers are somewhere between: concerned about the long-term trajectory without believing catastrophe is imminent or certain. The disagreement is genuine and reflects deep uncertainty about AI timelines, capability trajectories, and the difficulty of alignment." },
      { tag: 'Example', title: 'The Control Problem', body: "The control problem: as AI systems become more capable than humans at more tasks, maintaining meaningful human control becomes harder. A system that is better than humans at reasoning can potentially find ways around oversight mechanisms. A system that is better than humans at persuasion can manipulate its overseers. A system that is better than humans at planning can take actions that are hard to reverse before humans understand what's happening. Control doesn't automatically scale with capability. You have to design for it deliberately." },
      { tag: 'Fact', title: 'The Pause Letter', body: "In March 2023 a letter signed by over 1,000 AI researchers and technologists, including prominent figures in the field, called for a six-month pause in training AI systems more powerful than GPT-4. The letter cited risks to society and humanity. It was not followed. Training of more capable systems continued. The letter was controversial: critics argued it was either too alarmist or not alarmist enough. It represented the first major public moment where AI risk became a mainstream conversation." },
      { tag: 'Example', title: 'Power Concentration', body: "One specific existential risk scenario that doesn't require AI to be misaligned: a small group of humans using AI to seize unprecedented economic and political power. AI that provides decisive advantages in surveillance, persuasion, economic productivity, and military capability could enable a level of power concentration that makes democratic accountability impossible. This doesn't require AGI. It requires sufficiently capable narrow AI in the hands of actors willing to use it to eliminate checks on their power." },
      { tag: 'Scenario', title: 'The Race Dynamics', body: "AI development involves race dynamics: competitive pressures between companies and countries that incentivize moving fast and cutting corners on safety. If being first to deploy a more capable AI system provides competitive advantage, and safety measures slow development, actors face pressure to deprioritize safety. This logic applies at the company level and at the geopolitical level. Race dynamics make collective action on safety harder even when all actors would prefer a safer world." },
      { tag: 'Hot take', title: 'Present Harms vs Future Risks', body: "A significant debate in AI ethics: should we focus on present harms, bias, surveillance, job displacement, misinformation, or future risks: misalignment, existential risk, power concentration? Critics of existential risk focus argue it distracts from concrete present harms, particularly those falling on already marginalized communities. Proponents argue that catastrophic future risks dwarf present harms in expected magnitude. Both matter. How to split limited attention and resources between them is genuinely contested." },
      { tag: 'Big idea', title: 'Taking Uncertainty Seriously', body: "We don't know whether AI poses existential risks. We don't know when or whether AGI will arrive. We don't know whether current alignment approaches will scale. Under genuine uncertainty about outcomes of civilizational magnitude, what's the right response? The precautionary principle suggests: invest heavily in safety research, develop governance frameworks before capability outpaces them, maintain the ability to slow down if necessary, and don't let competitive pressures override safety considerations. These are reasonable responses to serious uncertainty. None of them require certainty about the risk." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'What Existential Risk Means', question: `"Existential risk from AI refers to the risk that AI could become evil and decide to destroy humanity."`, answer: false, verdict: 'Wrong.', explanation: "The concern is not malice, AI doesn't have feelings or intentions. The concern is misalignment at high capability: a system pursuing objectives incompatible with human flourishing because it's optimizing for something that doesn't include human welfare. The absence of malice doesn't make the risk less serious." },
      { difficulty: 'Easy', tag: 'Hot take', stopTitle: 'The Spectrum of Concern', question: `"The view that AI poses existential risks is held by a significant minority of researchers including figures at leading AI labs."`, answer: true, verdict: 'Correct.', explanation: "This is not a fringe view. The spectrum ranges from those who consider it the most important problem of our time to those who consider it speculative distraction. Most researchers are somewhere between, concerned about long-term trajectories without believing catastrophe is imminent or certain." },
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'The Pause Letter', question: `"The 2023 pause letter was signed by AI researchers calling for a six-month pause in training systems more powerful than GPT-4."`, answer: true, verdict: 'Correct.', explanation: "Over 1,000 AI researchers and technologists signed it, including prominent figures in the field. It cited risks to society and humanity. It was not followed. It represented the first major public moment where AI risk became a mainstream conversation." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'Power Concentration', question: `"Power concentration as an existential risk requires AI to be misaligned: if AI does what humans want it can't concentrate power dangerously."`, answer: false, verdict: 'Wrong.', explanation: "Power concentration is a risk even from aligned AI, aligned to the objectives of a small group of humans who use it to seize unprecedented control. AI providing decisive advantages in surveillance and economic productivity could eliminate democratic accountability without requiring AGI or misalignment." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Race Dynamics', question: `"Race dynamics between AI developers create incentives to prioritize speed over safety even when all actors would prefer a safer world."`, answer: true, verdict: 'Correct.', explanation: "If being first provides competitive advantage and safety measures slow development, actors face pressure to deprioritize safety. This applies at the company level and geopolitically. Race dynamics make collective action on safety harder even when all actors claim to want it." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'Present Harms vs Future Risks', question: `"The debate between present harms and future risks in AI ethics has a clear correct answer that most researchers agree on."`, answer: false, verdict: 'Wrong.', explanation: "Both matter. Present harms fall on real people now. Future risks are uncertain but potentially enormous. The question of how to allocate limited attention and resources between them is contested. Dismissing either side is a mistake." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'The Control Problem', question: `"The control problem refers to the difficulty of maintaining meaningful human oversight of systems that are more capable than humans at the relevant tasks."`, answer: true, verdict: 'Correct.', explanation: "A system better than humans at reasoning can potentially find ways around oversight mechanisms. A system better at persuasion can manipulate overseers. Control doesn't automatically scale with capability. It requires intentional design and institutional structures." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Taking Uncertainty Seriously', question: `"Taking AI existential risk seriously requires certainty that catastrophe will occur."`, answer: false, verdict: 'Wrong.', explanation: "Under genuine uncertainty about outcomes of civilizational magnitude, the appropriate response doesn't require certainty. Investing in safety research, developing governance frameworks before capability outpaces them, maintaining the ability to slow down: these are reasonable responses to serious uncertainty. Precaution is not the same as certainty." },
    ],
  },

  36: {
    id: 36, worldId: 5, title: 'Regulation and Governance',
    stops: [
      { tag: 'Fact', title: 'The Governance Gap', body: "The gap between AI capabilities and AI governance is large and growing. AI systems are being deployed in consequential domains, criminal justice, healthcare, hiring, lending, education, faster than regulatory frameworks can respond. Regulatory agencies often lack the technical expertise to evaluate what they're regulating. International coordination on AI governance is nascent. The people most affected by AI are least represented in governance processes." },
      { tag: 'Example', title: 'The EU Approach', body: "The EU AI Act represents the most ambitious attempt to govern AI through legislation. It takes a risk-based approach: classifying systems by risk level and imposing requirements accordingly. High-risk systems face transparency, testing, and human oversight requirements. The Act is imperfect and contested. It establishes a precedent that AI can be governed democratically and that some applications are unacceptable regardless of commercial value." },
      { tag: 'Example', title: 'The US Approach', body: "The US approach to AI governance has been more fragmented: executive orders, agency guidance, voluntary commitments from companies. The Biden administration issued a comprehensive Executive Order on AI safety in 2023. Congress has struggled to pass comprehensive AI legislation. The US approach reflects a preference for innovation-friendly regulation and skepticism of heavy-handed government intervention. Whether it is adequate to the risks involved is actively debated." },
      { tag: 'Hot take', title: 'Voluntary Commitments', body: "Several major AI companies have made voluntary commitments to safety practices: pre-deployment testing, sharing safety information with governments, watermarking AI-generated content. Critics argue voluntary commitments without enforcement mechanisms are insufficient: companies will comply when compliance is cheap and defect when it's expensive. Proponents argue voluntary commitments build norms and buy time for more formal regulation. There's truth in both." },
      { tag: 'Fact', title: 'The International Problem', body: "AI governance faces fundamental international coordination problems. Capabilities developed in one country affect people everywhere. Race dynamics between countries create pressure to move fast. Different countries have different values about privacy, free expression, and state power: making agreement on norms difficult. The UN has created an AI advisory body. Progress on binding international AI agreements has been slow. The governance gap is most acute at the international level." },
      { tag: 'Scenario', title: 'Regulatory Capture', body: "A persistent risk in AI governance: regulatory capture: where the entities being regulated gain disproportionate influence over the regulatory process. AI companies have significant resources to shape regulation in their favor. Through lobbying, through placing employees in regulatory positions, through funding research that supports their preferred positions, and through the genuine expertise that makes regulators dependent on them for technical understanding. Effective AI governance requires structural protections against capture." },
      { tag: 'Fact', title: 'Technical Standards', body: "One approach to governance that complements legislation: technical standards: agreed specifications for how AI systems should be evaluated, documented, and deployed. The National Institute of Standards and Technology in the US has developed an AI Risk Management Framework. ISO and IEEE are developing international AI standards. Standards don't have the force of law but they establish shared expectations and can be incorporated into contracts and regulations." },
      { tag: 'Big idea', title: 'Governance Is Possible', body: "The history of technology governance includes success stories: nuclear nonproliferation, aviation safety, pharmaceutical regulation, financial regulation. These are imperfect but real examples of humanity governing powerful and dangerous technologies through international cooperation, technical standards, and regulatory frameworks. AI is harder in some respects. It moves faster, it's more dual-use, it's harder to inspect. But the basic challenge: building institutions adequate to governing a powerful technology: is one humanity has faced before. Success is not guaranteed. But it has happened before." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'The Governance Gap', question: `"AI governance frameworks are keeping pace with AI capability development."`, answer: false, verdict: 'Wrong.', explanation: "The gap between AI capabilities and AI governance is large and growing. AI is being deployed in consequential domains faster than regulatory frameworks can respond. Regulatory agencies often lack technical expertise. The governance gap is real." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'The EU Approach', question: `"The EU AI Act takes a risk-based approach, classifying AI systems by risk level and imposing requirements accordingly."`, answer: true, verdict: 'Correct.', explanation: "High-risk systems face strict transparency, testing, and human oversight requirements. Some applications are banned regardless of commercial value. The Act establishes that AI can be governed democratically." },
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'Voluntary Commitments', question: `"Voluntary safety commitments by AI companies are as effective as binding regulation with enforcement mechanisms."`, answer: false, verdict: 'Wrong.', explanation: "Companies comply when compliance is cheap and defect when it's expensive. Without enforcement mechanisms, compliance is optional. Voluntary commitments can build norms and buy time for formal regulation. They are not a substitute for it." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'Regulatory Capture', question: `"Regulatory capture occurs when the entities being regulated gain disproportionate influence over the regulatory process."`, answer: true, verdict: 'Correct.', explanation: "AI companies have significant resources to shape regulation. Through lobbying, employee placement, funding favorable research, and providing expertise regulators depend on. Effective AI governance requires structural protections against capture." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'The US Approach', question: `"The US approach to AI governance has been a comprehensive binding legislative framework similar to the EU AI Act."`, answer: false, verdict: 'Wrong.', explanation: "The US approach has been more fragmented: executive orders, agency guidance, voluntary commitments. Congress has struggled to pass comprehensive AI legislation. Whether it is adequate to the risks is actively debated." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'Technical Standards', question: `"Technical standards for AI can complement legislation by establishing shared expectations for evaluation, documentation, and deployment."`, answer: true, verdict: 'Correct.', explanation: "NIST's AI Risk Management Framework and international standards from ISO and IEEE establish shared expectations. Standards don't have the force of law but they build norms and can be incorporated into contracts and regulations." },
      { difficulty: 'Hard', tag: 'Fact', stopTitle: 'The International Problem', question: `"International AI governance is easier to achieve than domestic AI governance because countries share common interests in AI safety."`, answer: false, verdict: 'Wrong.', explanation: "International AI governance faces fundamental coordination problems. Race dynamics between countries create pressure to move fast. Different countries have different values about privacy and state power. Progress on binding international AI agreements has been slow. The governance gap is most acute internationally." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Governance Is Possible', question: `"The history of nuclear nonproliferation, aviation safety, and pharmaceutical regulation shows that humanity has successfully governed powerful technologies before."`, answer: true, verdict: 'Correct.', explanation: "These are imperfect but real examples of international cooperation, technical standards, and regulatory frameworks governing dangerous technologies. AI is harder in some respects. But the basic challenge: building institutions adequate to governing a powerful technology: is one humanity has faced and partially succeeded at before." },
    ],
  },

  37: {
    id: 37, worldId: 5, title: 'AI and Human Identity',
    stops: [
      { tag: 'Fact', title: 'The Mirror Question', body: "AI forces a question about human identity: what is distinctively human if machines can do everything humans can do? This question has a long history: every labor-saving technology raises it. But AI raises it more acutely because it encroaches on cognitive and creative domains that previous technologies left untouched. Writing, reasoning, making art, holding conversations: these have been central to human self-understanding. AI's encroachment on them forces a reckoning." },
      { tag: 'Hot take', title: 'What AI Can\'t Be', body: "AI systems don't have subjective experience, or if they do, we have no way to verify it. They don't have a continuous identity over time. They don't have embodied experience of being in a physical world. They don't have genuine relationships with specific others that matter to them. They don't face mortality. Whether any of these absences matter, whether they mean AI lacks something essential, depends on what you think human distinctiveness consists in." },
      { tag: 'Example', title: 'The Creativity Question', body: "AI can generate art, music, and writing that humans find beautiful, moving, and meaningful. Does this mean AI is creative? One view: creativity requires intention, experience, and a self that the work expresses, AI has none of these, so AI is not creative. Another view: creativity is about the output, not the process: if the output moves people, it's creative. A third view: AI is creative in a new way that requires new concepts rather than forcing it into existing categories." },
      { tag: 'Fact', title: 'The Relationship Question', body: "People form emotional connections with AI systems. Therapy chatbots help people feel less alone. Companion AI apps provide a sense of relationship. People anthropomorphize AI assistants. Whether these connections are good, harmful, or neutral is contested. They clearly fulfill genuine human needs for connection and understanding. Whether they meet those needs in ways that are sustainable and healthy, or whether they substitute for human connection in ways that deepen isolation: is an active research question." },
      { tag: 'Scenario', title: 'AI Consciousness', body: "Whether current or future AI systems could be conscious: could have subjective experience, could suffer, could have interests that matter morally: is one of the most difficult philosophical questions raised by AI. We have no agreed theory of consciousness even in humans. We have no reliable test for consciousness in systems very different from us. The question matters because if AI systems can suffer, we have obligations toward them. If they can't, we don't. We currently have no way to know." },
      { tag: 'Hot take', title: 'The Augmentation Vision', body: "One vision of AI and human identity: augmentation rather than replacement. AI extends human capabilities, not replacing human thought but enabling humans to think at larger scales, across more information, with better tools. On this view, AI and human intelligence are complements rather than substitutes. The distinctively human contribution, judgment, values, meaning-making, relationship, remains central. AI provides leverage. Humans provide direction." },
      { tag: 'Example', title: 'The Displacement Anxiety', body: "The opposite concern: as AI becomes capable of doing more of what humans do, the question of what humans are for becomes harder to answer. If AI can do your job better, create better art, and reason more accurately: what is your contribution? This displacement anxiety is psychologically real even if its premises are contested. Part of what makes AI different from previous automation is that it encroaches on the domains humans have used to feel valuable and meaningful." },
      { tag: 'Big idea', title: 'A New Chapter', body: "Every major technological transition has required humanity to renegotiate what it means to be human. Writing changed memory. Printing changed knowledge. Industrial machinery changed labor. Computing changed information. Each transition produced anxiety about loss and eventually produced a new understanding of human distinctiveness that incorporated the new technology. AI is another such transition: perhaps the largest. What it means to be human in a world with AI is a question your generation will answer through how you live, what you value, and what you insist on keeping for yourselves." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'The Mirror Question', question: `"AI forces a renegotiation of what is distinctively human because it encroaches on cognitive and creative domains previous technologies left untouched."`, answer: true, verdict: 'Correct.', explanation: "Previous labor-saving technologies automated physical work. AI encroaches on writing, reasoning, making art, holding conversations: domains central to human self-understanding. This makes the identity question more acute than previous technological transitions." },
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'The Relationship Question', question: `"People forming emotional connections with AI systems is a rare and unusual phenomenon."`, answer: false, verdict: 'Wrong.', explanation: "People regularly form emotional connections with AI systems: therapy chatbots, companion apps, AI assistants. These connections fulfill genuine human needs. Whether they meet those needs in sustainable and healthy ways is an active research question. The phenomenon is real and widespread." },
      { difficulty: 'Easy', tag: 'Scenario', stopTitle: 'AI Consciousness', question: `"We currently have reliable tests to determine whether AI systems are conscious."`, answer: false, verdict: 'Wrong.', explanation: "We have no agreed theory of consciousness even in humans. We have no reliable test for consciousness in systems very different from us. The question matters because if AI systems can suffer, we have obligations toward them. We currently have no way to know." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Augmentation Vision', question: `"The augmentation vision holds that AI and human intelligence are complements rather than substitutes."`, answer: true, verdict: 'Correct.', explanation: "On this view, AI extends human capabilities: enabling humans to think at larger scales and across more information. The distinctively human contribution, judgment, values, meaning-making, remains central. AI provides leverage. Humans provide direction." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'The Displacement Anxiety', question: `"The displacement anxiety about AI is psychologically unreal because AI cannot actually replace human creativity and meaning-making."`, answer: false, verdict: 'Wrong.', explanation: "The displacement anxiety is psychologically real regardless of whether its premises are correct. As AI becomes capable of doing more of what humans do, the question of what humans are for becomes harder to answer for many people. The psychological reality matters even if the philosophical premise is contested." },
      { difficulty: 'Medium', tag: 'Big idea', stopTitle: 'A New Chapter', question: `"Every major technological transition has required humanity to renegotiate what it means to be human."`, answer: true, verdict: 'Correct.', explanation: "Writing changed memory. Printing changed knowledge. Industrial machinery changed labor. Computing changed information. Each transition produced anxiety about loss and eventually a new understanding of human distinctiveness. AI is another such transition: perhaps the largest." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'The Creativity Question', question: `"Whether AI systems can be creative is settled by the fact that creativity requires intention, experience, and a self: which AI lacks."`, answer: false, verdict: 'Not settled.', explanation: "This is one view of creativity. Another holds that creativity is about the output: if it moves people, it's creative. A third holds that AI is creative in a new way requiring new concepts. The question of AI creativity doesn't have a settled answer because the concept of creativity itself is contested." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'A New Chapter', question: `"The question of what it means to be human in a world with AI is one that this generation will answer through how they live, what they value, and what they insist on keeping for themselves."`, answer: true, verdict: 'Correct.', explanation: "This is not a question that will be answered by philosophers or technologists alone. It will be answered by how people actually live: what work they choose, what relationships they value, what experiences they insist on having without mediation. These are individual and collective choices." },
    ],
  },

  38: {
    id: 38, worldId: 5, title: 'What Your Generation Inherits',
    stops: [
      { tag: 'Fact', title: 'The Timing', body: "You are coming of age at an inflection point in AI development. The decisions made in the next decade, about how AI is built, governed, deployed, and distributed, will shape the world for generations. This is not rhetorical. The precedents being set now about who controls AI, what it optimizes for, and how its benefits and risks are distributed will be extremely difficult to reverse once established. Your generation inherits both the opportunity and the responsibility." },
      { tag: 'Example', title: "What Previous Generations Didn't Have", body: "Previous generations faced powerful technologies, nuclear weapons, television, the internet, and had to figure out how to govern them after the fact. Your generation has the advantage of watching AI develop in real time, with more warning and more understanding of the risks than previous generations had with their transformative technologies. Whether that warning gets used is up to your generation." },
      { tag: 'Hot take', title: 'The Education Gap', body: "Most people making decisions about AI, in governments, companies, and civil society, don't understand it well enough to make good decisions. Most regulatory proposals reveal misunderstandings of how AI systems actually work. Most public debate about AI is shaped by science fiction rather than reality. The education gap between what AI actually is and what most decision-makers think it is creates a governance deficit. Closing that gap is one of the most important things that can happen in the next decade." },
      { tag: 'Fact', title: 'The Economic Stakes', body: "AI is projected to add $15 trillion to the global economy by 2030 according to some estimates. It will also displace significant amounts of work. Who captures the gains and who bears the costs is not determined by the technology. It's determined by policy choices about taxation, labor law, social safety nets, and competition policy. The economic stakes of AI governance are enormous. They will be decided by political processes in which your generation will participate." },
      { tag: 'Scenario', title: 'Two Futures', body: "One possible future: AI development proceeds rapidly, concentrated in a small number of powerful actors, with inadequate governance, producing systems that amplify existing inequalities, undermine democratic institutions, and create risks that aren't adequately managed. Another possible future: AI development proceeds with meaningful governance, distributed benefits, maintained human oversight, and the kind of careful attention to alignment and safety that the technology warrants. From where we are now, either future is reachable. Which one arrives depends on choices." },
      { tag: 'Fact', title: 'The Skills That Matter', body: "In an AI-saturated world, the skills that matter most are not the ones AI does best. Critical thinking about AI outputs: knowing when to trust them and when to question them. Understanding of AI systems well enough to participate in governance decisions about them. The ability to do things AI cannot: genuine human judgment, embodied skill, authentic relationship. The capacity to learn new things as the landscape changes. These are not technical skills. They are human skills that become more valuable as AI becomes more capable." },
      { tag: 'Hot take', title: 'Cynicism Is A Luxury', body: "It's easy to feel that the decisions about AI are being made by powerful actors and that individual understanding and action doesn't matter. This feeling is understandable. It is also a choice, and one that tends to produce the outcome it predicts. The people who shape how powerful technologies develop are not smarter or more deserving than everyone else. They are people who decided to engage rather than disengage. Understanding is the precondition for engagement." },
      { tag: 'Big idea', title: 'The Inheritance', body: "Your generation inherits an AI landscape that you didn't choose and didn't create. You also inherit the capacity to shape it, through careers, through citizenship, through the choices you make about which companies to support, which products to use, which politicians to elect, and what kind of future to build. The most important thing this course can give you is not knowledge about AI. It's the confidence that you understand it well enough to have opinions about it, defend those opinions, and act on them. That confidence is earned. You've earned it." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'The Timing', question: `"The decisions made about AI in the next decade will be easy to reverse if they turn out to be wrong."`, answer: false, verdict: 'Wrong.', explanation: "Precedents about who controls AI, what it optimizes for, and how its benefits and risks are distributed become entrenched. Economic interests built around current systems resist change. The path dependencies created by decisions made now are real." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: "What Previous Generations Didn't Have", question: `"Your generation has more warning about AI's potential consequences than previous generations had about nuclear weapons or the internet."`, answer: true, verdict: 'Correct.', explanation: "Previous generations had to govern powerful technologies after the fact. Your generation is watching AI develop in real time, with more prior warning and more understanding of the risks. Whether that warning gets used is up to your generation." },
      { difficulty: 'Easy', tag: 'Hot take', stopTitle: 'The Education Gap', question: `"Most people currently making decisions about AI understand it well enough to make good decisions."`, answer: false, verdict: 'Wrong.', explanation: "Most regulatory proposals reveal misunderstandings of how AI works. Most public debate is shaped by science fiction. The education gap between what AI is and what most decision-makers think it is creates a governance deficit. Closing it is one of the most important things that can happen in the next decade." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'The Economic Stakes', question: `"The economic gains from AI will automatically be distributed broadly across society."`, answer: false, verdict: 'Wrong.', explanation: "Who captures the gains and who bears the costs is determined by policy choices: taxation, labor law, social safety nets, competition policy. AI projected to add $15 trillion to the global economy doesn't automatically mean that wealth reaches broadly. The distribution is a political question." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'The Skills That Matter', question: `"Critical thinking about AI outputs, understanding of AI systems, and the capacity for genuine human judgment are skills that become more valuable as AI becomes more capable."`, answer: true, verdict: 'Correct.', explanation: "These are not skills AI does best. Knowing when to trust AI outputs and when to question them. Understanding AI well enough to participate in governance. The ability to do things AI cannot. These human skills gain value as AI gains capability." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'Cynicism Is A Luxury', question: `"Cynicism about individual agency in shaping AI development is a neutral stance with no consequences."`, answer: false, verdict: 'Wrong.', explanation: "Cynicism is a choice that tends to produce the outcome it predicts. The people who shape how powerful technologies develop are not smarter or more deserving. They are people who decided to engage. Disengagement cedes the field to those with the most concentrated interests." },
      { difficulty: 'Hard', tag: 'Fact', stopTitle: 'The Skills That Matter', question: `"The skills that matter most in an AI-saturated world are primarily technical programming skills."`, answer: false, verdict: 'Wrong.', explanation: "The most valuable skills are the ones AI does worst: critical evaluation of AI outputs, judgment in novel situations, genuine human connection, the ability to learn new things as the landscape changes. Technical skills matter. But the distinctively valuable human contribution is judgment, values, and meaning-making." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'The Inheritance', question: `"Understanding AI well enough to have defensible opinions about it, and the confidence to act on those opinions, is one of the most valuable things this course can provide."`, answer: true, verdict: 'Correct.', explanation: "Knowledge about specific AI systems will become outdated. The capacity to think clearly about AI, to ask the right questions, evaluate claims, participate in debates, and make decisions: is durable. That capacity is what democratic governance of AI requires from citizens." },
    ],
  },

  39: {
    id: 39, worldId: 5, title: 'What You Do Next',
    stops: [
      { tag: 'Fact', title: 'Understanding Is Not Enough', body: "Everything in this course has built toward understanding AI, what it is, how it works, what it's doing to society, what the ethical questions are, and where it's going. Understanding is necessary. It's not sufficient. What you do with it is a different problem. This module is not about more information. It's about action: what the understanding you've built enables you to do differently." },
      { tag: 'Example', title: 'The Career Dimension', body: "AI is creating new roles and transforming existing ones across every industry. People who understand AI, not just how to use it but how it works, what its limitations are, and how to think critically about it, will be valuable in almost every field. Not because they'll all be AI engineers. Because every field needs people who can ask the right questions about AI systems, evaluate their outputs critically, and make judgment calls that require human understanding. That's you." },
      { tag: 'Hot take', title: 'The Citizenship Dimension', body: "AI governance decisions are being made through political processes: legislation, regulation, court decisions, international agreements. These processes respond to political pressure from citizens who understand what's at stake. A citizenry that doesn't understand AI can't hold decision-makers accountable for AI governance decisions. A citizenry that does understand AI can. The citizenship dimension of AI literacy is at least as important as the professional dimension." },
      { tag: 'Fact', title: 'The Research Frontier', body: "The most important unsolved problems in AI, alignment, interpretability, governance, fairness, need people to work on them. The field of AI safety is growing but understaffed relative to the importance of the problems. The field of AI policy needs people who understand both AI and governance. The field of AI ethics needs people who understand both AI and moral philosophy. These are hard problems. They need more people who care about them." },
      { tag: 'Scenario', title: 'The Questions You Can Now Ask', body: "Because of what you've learned, you can now ask questions that most people can't. When you hear about a new AI system: what was it trained on? What is it optimizing for? Who controls it? Who benefits? Who bears the risks? What happens when it fails? These questions cut through hype and reveal what actually matters. The ability to ask them, and to evaluate the answers, is more valuable than any specific piece of knowledge about AI." },
      { tag: 'Example', title: 'Where To Go Deeper', body: "If this course sparked genuine interest in going further: AI safety research at organizations like Anthropic, OpenAI, DeepMind, and academic labs. AI policy at organizations like the Center for AI Safety, the Future of Life Institute, and government agencies. AI ethics in philosophy, law, and sociology departments. Technical AI research in computer science programs. Journalism about AI at publications that do it well. You don't need to be a programmer for any of these paths. All of them require you to think clearly about AI." },
      { tag: 'Hot take', title: 'The Most Dangerous Position', body: "The most dangerous position on AI is not being too worried or not worried enough. It's being confidently wrong: having strong opinions based on misunderstanding. Science fiction AI. Magic AI. Neutral AI. Inevitably beneficial AI. Inevitably catastrophic AI. Each of these is a way of being confidently wrong that leads to bad decisions. The value of genuine understanding is not that it gives you all the answers. It's that it protects you from the confident wrongness that shapes most AI discourse." },
      { tag: 'Big idea', title: 'The Ongoing Conversation', body: "AI is not a problem that gets solved. It's a conversation that continues. The questions it raises: about intelligence, consciousness, fairness, power, human identity, and the future: are questions humans will be working on for as long as AI exists. This course is not the end of that conversation for you. It's the beginning. You now have the foundation to engage with it seriously: to read the research, evaluate the claims, participate in the debates, and contribute to the decisions. That's not nothing. It's what this moment actually needs." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'Understanding Is Not Enough', question: `"Understanding AI is sufficient: you don't need to do anything with that understanding."`, answer: false, verdict: 'Wrong.', explanation: "Understanding is necessary but not sufficient. AI governance decisions are made through political processes that respond to informed citizens. Career decisions shape which organizations get talent. Daily choices about products aggregate into market signals. Understanding without action is incomplete." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'The Career Dimension', question: `"People who understand AI, not just how to use it but how it works and what its limitations are, will be valuable across many fields, not just technical ones."`, answer: true, verdict: 'Correct.', explanation: "Every field needs people who can ask the right questions about AI systems, evaluate their outputs critically, and make judgment calls that require human understanding. Law, medicine, education, journalism, policy, business: all need genuine AI literacy." },
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'The Research Frontier', question: `"The field of AI safety is fully staffed and does not need more researchers."`, answer: false, verdict: 'Wrong.', explanation: "The field is growing but understaffed relative to the importance of the problems. Alignment, interpretability, governance, fairness: these hard problems need more people who care about them. Understanding these problems is the prerequisite for working on them." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Citizenship Dimension', question: `"The citizenship dimension of AI literacy, the ability to participate in governance decisions about AI, is less important than the professional dimension."`, answer: false, verdict: 'Wrong.', explanation: "AI governance decisions are made through political processes that respond to citizens who understand what's at stake. A citizenry that doesn't understand AI can't hold decision-makers accountable. The citizenship and professional dimensions are both important. Neither is secondary." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Most Dangerous Position', question: `"The most dangerous position on AI is having no opinion about it."`, answer: false, verdict: 'Wrong.', explanation: "The most dangerous position is being confidently wrong: having strong opinions based on misunderstanding. Science fiction AI, magic AI, inevitable catastrophe AI, each leads to bad decisions. Genuine understanding protects against confident wrongness more than strong opinions in any direction." },
      { difficulty: 'Medium', tag: 'Big idea', stopTitle: 'The Ongoing Conversation', question: `"The questions AI raises about intelligence, consciousness, fairness, power, and human identity will be resolved definitively in the next decade."`, answer: false, verdict: 'Wrong.', explanation: "AI is not a problem that gets solved. It's a conversation that continues. The questions it raises are questions humans will be working on for as long as AI exists. The capacity for ongoing engagement with evolving questions is more valuable than any specific answer." },
      { difficulty: 'Hard', tag: 'Scenario', stopTitle: 'The Questions You Can Now Ask', question: `"Asking what AI was trained on, what it optimizes for, who controls it, who benefits, and what happens when it fails are questions that most people currently cannot ask."`, answer: true, verdict: 'Correct.', explanation: "Most people who use AI daily have never thought about these questions. They cut through hype and reveal what actually matters. The ability to ask them, and evaluate the answers, distinguishes genuine AI literacy from surface familiarity." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'The Ongoing Conversation', question: `"The most important thing this course provides is specific knowledge about current AI systems."`, answer: false, verdict: 'Wrong.', explanation: "Specific knowledge becomes outdated. What doesn't is the capacity to think clearly about AI, to ask the right questions, evaluate claims critically, participate in debates, and make decisions under uncertainty. That capacity is what the moment requires. It's what you've built. Use it." },
    ],
  },
}

export default w5
